const input = $input.first().json.body || $input.first().json;
const { interaction_type, entity_type, entity_id, action, context, result, content, content_type, title, decision_type, decision, reasoning, factors, opportunity_id, confidence, source, user_context, metadata } = input;
const esc = (s) => (s || '').replace(/'/g, "''").replace(/\\/g, '\\\\');

// Simple hash without crypto
const simpleHash = (str) => {
  let h = 0;
  for (let i = 0; i < str.length; i++) { h = ((h << 5) - h) + str.charCodeAt(i); h |= 0; }
  return 'h' + Math.abs(h).toString(36) + str.length.toString(36);
};

const parts = [];

if (interaction_type && action) {
  parts.push(`INSERT INTO gda_interaction_log (interaction_type, entity_type, entity_id, action, context, result) VALUES ('${esc(interaction_type)}', '${esc(entity_type || '')}', ${entity_id || 'NULL'}, '${esc(action)}', '${esc(JSON.stringify(context || {}))}'::jsonb, '${esc(JSON.stringify(result || {}))}'::jsonb)`);
}

if (decision_type && decision) {
  parts.push(`INSERT INTO gda_decision_memory (opportunity_id, decision_type, decision, confidence, reasoning, factors, decision_by) VALUES (${opportunity_id || 'NULL'}, '${esc(decision_type)}', '${esc(decision)}', ${confidence || 0}, '${esc(reasoning || '')}', '${esc(JSON.stringify(factors || {}))}'::jsonb, '${esc(input.decision_by || 'user')}')`);
}

if (content && content_type) {
  const hash = simpleHash(content);
  parts.push(`INSERT INTO gda_content_store (content_type, source_table, source_id, title, content, content_hash, metadata, token_count) VALUES ('${esc(content_type)}', '${esc(entity_type || '')}', ${entity_id || 'NULL'}, '${esc(title || '')}', '${esc(content)}', '${hash}', '${esc(JSON.stringify(metadata || {}))}'::jsonb, ${Math.ceil((content || '').length / 4)}) ON CONFLICT (content_hash) DO UPDATE SET content = EXCLUDED.content, embedding_status = 'pending'`);
}

const learnContent = content || reasoning || JSON.stringify(result || {});
if (learnContent && learnContent !== '{}') {
  const dt = decision_type || interaction_type || content_type || 'general';
  parts.push(`INSERT INTO gda_learning_log (data_type, source, content, metadata, user_context) VALUES ('${esc(dt)}', '${esc(source || 'platform')}', '${esc(learnContent)}', '${esc(JSON.stringify({entity_type, entity_id, action, ...(metadata || {})}))}'::jsonb, '${esc(user_context || '')}')`);
}

const combined = parts.join('; ') + ';';
return [{ json: { command: `docker exec n8n-envision-postgres-1 psql -U n8n -d n8n -c \"${combined.replace(/\"/g, '\\\"')}\"`, query_count: parts.length } }];

const raw = $input.first().json.content || '';
const stats = {};
raw.split('\n').filter(Boolean).forEach(line => {
  const [key, val] = line.split('|');
  if (key && val) stats[key.trim()] = parseInt(val.trim()) || 0;
});
const queryCount = $('Build Queries').first().json.query_count;
return [{ json: { success: true, queries_executed: queryCount, memory_stats: stats, timestamp: new Date().toISOString() } }];
